using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Services;

/// <summary>
/// Server-side implementation that accesses data directly (in-memory store for demo).
/// In production, replace with EF Core DbContext access.
/// </summary>
public class ServerShipmentService : IShipmentService
{
    private static readonly List<Shipment> _shipments = GenerateSeedData();

    public Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return Task.FromResult(_shipments.ToList());
    }

    public Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var shipment = _shipments.FirstOrDefault(
            s => s.TrackingNumber.Equals(trackingNumber, StringComparison.OrdinalIgnoreCase));
        return Task.FromResult(shipment);
    }

    public Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus newStatus)
    {
        var shipment = _shipments.FirstOrDefault(s => s.Id == id);
        if (shipment is null)
            return Task.FromResult<Shipment?>(null);

        shipment.Status = newStatus;
        return Task.FromResult<Shipment?>(shipment);
    }

    private static List<Shipment> GenerateSeedData()
    {
        return
        [
            new Shipment
            {
                Id = 1, TrackingNumber = "TRK-100201",
                Origin = "New York, NY", Destination = "Los Angeles, CA",
                Status = ShipmentStatus.InTransit,
                ShippedDate = DateTime.UtcNow.AddDays(-3),
                EstimatedDelivery = DateTime.UtcNow.AddDays(2),
                CustomerEmail = "alice@example.com",
                Description = "Electronics - 2 boxes"
            },
            new Shipment
            {
                Id = 2, TrackingNumber = "TRK-100202",
                Origin = "Chicago, IL", Destination = "Miami, FL",
                Status = ShipmentStatus.PickedUp,
                ShippedDate = DateTime.UtcNow.AddDays(-1),
                EstimatedDelivery = DateTime.UtcNow.AddDays(4),
                CustomerEmail = "bob@example.com",
                Description = "Furniture - 1 pallet"
            },
            new Shipment
            {
                Id = 3, TrackingNumber = "TRK-100203",
                Origin = "Seattle, WA", Destination = "Denver, CO",
                Status = ShipmentStatus.Delivered,
                ShippedDate = DateTime.UtcNow.AddDays(-7),
                EstimatedDelivery = DateTime.UtcNow.AddDays(-2),
                CustomerEmail = "carol@example.com",
                Description = "Medical supplies - 5 boxes"
            },
            new Shipment
            {
                Id = 4, TrackingNumber = "TRK-100204",
                Origin = "Dallas, TX", Destination = "Boston, MA",
                Status = ShipmentStatus.Delayed,
                ShippedDate = DateTime.UtcNow.AddDays(-5),
                EstimatedDelivery = DateTime.UtcNow.AddDays(1),
                CustomerEmail = "dave@example.com",
                Description = "Auto parts - 3 crates"
            },
            new Shipment
            {
                Id = 5, TrackingNumber = "TRK-100205",
                Origin = "San Francisco, CA", Destination = "Portland, OR",
                Status = ShipmentStatus.OutForDelivery,
                ShippedDate = DateTime.UtcNow.AddDays(-2),
                EstimatedDelivery = DateTime.UtcNow,
                CustomerEmail = "eve@example.com",
                Description = "Clothing - 1 box"
            },
            new Shipment
            {
                Id = 6, TrackingNumber = "TRK-100206",
                Origin = "Atlanta, GA", Destination = "Phoenix, AZ",
                Status = ShipmentStatus.Pending,
                ShippedDate = DateTime.UtcNow,
                EstimatedDelivery = DateTime.UtcNow.AddDays(5),
                CustomerEmail = "frank@example.com",
                Description = "Food products - 2 pallets (refrigerated)"
            }
        ];
    }
}

using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (IShipmentService service) =>
        {
            var shipments = await service.GetAllShipmentsAsync();
            return Results.Ok(shipments);
        }).RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetByTrackingNumberAsync(trackingNumber);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        }).RequireAuthorization();

        group.MapPut("/{id:int}/status", async (int id, ShipmentStatus newStatus, IShipmentService service) =>
        {
            var shipment = await service.UpdateStatusAsync(id, newStatus);
            return shipment is not null ? Results.Ok(shipment) : Results.NotFound();
        }).RequireAuthorization();
    }
}

